mapper.select:
/* 회사 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
			from tb_company
			where del_yn = 'N'
			
			and comp_idx = #{compIdx }
			
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
 
limit #{startNum }, #{pageRowCnt }

/* 회사 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
			from tb_company
			where del_yn = 'N'
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 그룹 목록 조회 */
select * from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name, 
				a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname, 
				a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date
			from tb_site_group a, tb_company b
			where a.comp_idx = b.comp_idx
			and a.del_yn = 'N'
			
			and a.comp_idx = #{compIdx }
			
			 
			and a.site_grp_idx = #{siteGrpIdx }
			
			order by a.reg_date desc
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb
 
limit #{startNum }, #{pageRowCnt }

/* 그룹 목록 건수 조회 */
select 
	count(*) as listCnt 
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select 
				a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name, 
				a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname, 
				a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date
			from tb_site_group a, tb_company b
			where a.comp_idx = b.comp_idx
			and a.del_yn = 'N'
			
			and a.comp_idx = #{compIdx }
			
			 
			and a.site_grp_idx = #{siteGrpIdx }
			
			
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 사이트 목록 조회 */ select * from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.site_id, a.user_idx, a.site_name, a.site_grp_idx, a.area_type, a.`time_zone`, a.local_ems_addr, a.local_ems_key, a.comp_idx, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date , b.site_grp_name, c.device_type_nms from tb_site a left outer join tb_site_group b on a.site_grp_idx = b.site_grp_idx left outer join ( select site_id, group_concat(device_type_nm) as device_type_nms from ( select site_id, device_type, case device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' else 'ESS모니터링기기' end as device_type_nm from tb_device group by site_id, device_type ) a group by site_id ) c on a.site_id = c.site_id where 1=1 and a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
order by a.reg_date ) page_tb , ( select @rownum := 0 ) r ) f_tb
limit #{startNum }, #{pageRowCnt }

/* 사이트 목록 건수 조회 */ select count(*) as listCnt from ( select @rownum := @rownum + 1 as rnum, page_tb.* from ( select a.site_id, a.user_idx, a.site_name, a.site_grp_idx, a.area_type, a.`time_zone`, a.local_ems_addr, a.local_ems_key, a.comp_idx, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date , b.site_grp_name, c.device_type_nms from tb_site a left outer join tb_site_group b on a.site_grp_idx = b.site_grp_idx left outer join ( select site_id, group_concat(device_type_nm) as device_type_nms from ( select site_id, device_type, case device_type when 1 then 'PCS' when 2 then 'BMS' when 3 then 'PV' when 4 then '부하측정기기' when 5 then 'PV모니터링기기' else 'ESS모니터링기기' end as device_type_nm from tb_device group by site_id, device_type ) a group by site_id ) c on a.site_id = c.site_id where 1=1 and a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
) page_tb , ( select @rownum := 0 ) r ) f_tb

/* 회사 내 그룹 목록(팝업) 조회 */ select a.site_grp_idx, a.user_idx, a.site_grp_id, a.site_grp_name, a.comp_idx, b.comp_id, b.comp_name, a.site_grp_img_path, a.site_grp_img_sname, a.site_grp_img_rname, a.del_yn, a.reg_uid, a.reg_date, a.mod_uid, a.mod_date from tb_site_group a, tb_company b where a.comp_idx = b.comp_idx and a.del_yn = 'N'
and a.comp_idx = #{compIdx }
and a.site_grp_idx = #{siteGrpIdx }
order by a.site_grp_name

/* 사이트 목록(사이트그룹 내) 조회 */
select 
	site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, 
	local_ems_addr, local_ems_key, comp_idx, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site
where del_yn = 'N'

and comp_idx = #{compIdx}

 
and site_grp_idx = #{siteGrpIdx }

 
and site_id = #{siteId }

order by reg_date

/* 사이트 목록(고객사 전체중 특정사이트그룹 제외) 조회 */
select 
	site_id, user_idx, site_name, site_grp_idx, area_type, `time_zone`, 
	local_ems_addr, local_ems_key, comp_idx, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site
where del_yn = 'N'

and comp_idx = #{compIdx}

 
and user_idx = #{userIdx }

 
and (site_grp_idx != #{siteGrpIdx } or site_grp_idx is null)

order by reg_date

/* 상단 사이트그룹 목록 조회 */
select
	site_grp_idx, user_idx, site_grp_id, site_grp_name, comp_idx
from tb_site_group
where del_yn = 'N'

and comp_idx = #{compIdx}


and site_grp_idx = #{siteGrpIdx}


and user_idx = #{userIdx}

order by site_grp_name

/* 상단 사이트 목록 조회 */
select
	a.site_id, a.site_name, a.site_grp_idx, a.comp_idx
from tb_site a, tb_site_group b
where 1=1
and a.site_grp_idx = b.site_grp_idx
and a.del_yn = 'N'

and a.comp_idx = #{compIdx}


and a.site_grp_idx = #{siteGrpIdx}


and a.user_idx = #{userIdx}

order by a.site_name

		/* 군관리메인 사이트 사용량 순위 목록 조회 */
		select * from (
			select
				@rownum := @rownum + 1 as rnum,
				page_tb.*
			from (
					select
						a.site_id, a.site_name,

						(select truncate(ifnull(sum(usg_val), 0) / 1000000, 0) from tb_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) "usage",
						(select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge,
						(select ifnull(sum(gen_val), 0) from tb_pv_gen where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) gen,
						(
							(select ifnull(sum(off_peak_rate + mid_peak_rate + max_peak_rate), 0) from tb_bill where site_id = a.site_id and bill_yearm between #{selTermFrom } and #{selTermTo }) +
							(select ifnull(sum(tot_price), 0) from tb_gen_revenue where site_id = a.site_id and gen_type = '1' and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) +
							(select ifnull(sum(((reduct_amt / reduct_cap) * 100) + 123), 0) from tb_dr_revenue where site_id = a.site_id and std_yearm between #{selTermFrom } and #{selTermTo })
						) reward,

						(select truncate(ifnull(sum(pre_usg_val), 0) / 1000000, 0) from tb_predict_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) usage_plan,
						(select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge_plan where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge_plan
					from tb_site a, tb_site_group b
					where 1=1
					and a.site_grp_idx = b.site_grp_idx
					and a.del_yn = 'N'
					
					
					
					and a.user_idx = #{userIdx}
					
					and a.area_type = #{areaType}
					
					
					
					and b.site_grp_idx = #{grpIdx}
					
					
					and b.user_idx = #{userIdx}
					
					
					
			) page_tb
			,  ( select @rownum := 0 ) r
			order by #{rankType} desc
		) f_tb
		
		limit #{startNum }, #{pageRowCnt }

/* 군관리메인 사이트 사용량 순위 목록 건수 조회 (군관리메인 사이트 목록 건수 조회와 동일) */
select 
	count(*) as listCnt
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.site_id, a.site_name
			from tb_site a, tb_site_group b
			where 1=1
			and a.site_grp_idx = b.site_grp_idx
			and a.del_yn = 'N'
			
			
			
			and a.user_idx = #{userIdx}
			
			and a.area_type = #{areaType}
			
			
			
			and b.site_grp_idx = #{grpIdx}
			
			
			and b.user_idx = #{userIdx}
			
			
			
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

		/* 군관리메인 사이트 목록 조회 */
		select * from (
			select
				@rownum := @rownum + 1 as rnum,
				page_tb.*
			from (
					select
						a.site_id, a.site_name, b.site_grp_idx,

						(select count(reg_date) from tb_device_ioe where site_id = a.site_id) ioe,
						(select count(reg_date) from tb_device_pcs where site_id = a.site_id) pcs,
						(select count(reg_date) from tb_device_bms where site_id = a.site_id) bms,
						(select count(reg_date) from tb_device_pv where site_id = a.site_id) pv,

						(select truncate(ifnull(sum(usg_val), 0) / 1000000, 0) from tb_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) "usage",
						(select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge,
						(select ifnull(sum(gen_val), 0) from tb_pv_gen where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) gen,
						(
							(select ifnull(sum(off_peak_rate + mid_peak_rate + max_peak_rate), 0) from tb_bill where site_id = a.site_id and bill_yearm between #{selTermFrom } and #{selTermTo }) +
							(select ifnull(sum(tot_price), 0) from tb_gen_revenue where site_id = a.site_id and gen_type = '1' and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) +
							(select ifnull(sum(((reduct_amt / reduct_cap) * 100) + 123), 0) from tb_dr_revenue where site_id = a.site_id and std_yearm between #{selTermFrom } and #{selTermTo })
						) reward
					from tb_site a, tb_site_group b
					where 1=1
					and a.site_grp_idx = b.site_grp_idx
					and a.del_yn = 'N'
					
					
					
					and a.user_idx = #{userIdx}
					
					and a.area_type = #{areaType}
					
					
					
					and b.site_grp_idx = #{grpIdx}
					
					
					and b.user_idx = #{userIdx}
					
					
					
					order by a.site_name
			) page_tb
			,  ( select @rownum := 0 ) r
		) f_tb
		
		limit #{startNum }, #{pageRowCnt }

/* 군관리메인 사이트 목록 건수 조회 */
select 
	count(*) as listCnt
from (
	select 
		@rownum := @rownum + 1 as rnum,
		page_tb.*
	from (
			select
				a.site_id, a.site_name, b.site_grp_idx
			from tb_site a, tb_site_group b
			where 1=1
			and a.site_grp_idx = b.site_grp_idx
			and a.del_yn = 'N'
			
			
			
			and a.user_idx = #{userIdx}
			
			and a.area_type = #{areaType}
			
			
			
			and b.site_grp_idx = #{grpIdx}
			
			
			and b.user_idx = #{userIdx}
			
			
			
	) page_tb
	,  ( select @rownum := 0 ) r
) f_tb

/* 군관리메인 사이트그룹 목록 조회 */ select site_grp_idx, user_idx, site_grp_id, site_grp_name from tb_site_group where del_yn = 'N'
and user_idx = #{userIdx}
order by site_grp_name

/* 회사 한건 조회 */
select 
	comp_idx, user_idx, comp_id, comp_name, del_yn, reg_uid, reg_date, mod_uid, mod_date
from tb_company
where del_yn = 'N'
and comp_idx = #{compIdx }

/* 그룹 한건 조회 */
select 
	site_grp_idx, user_idx, site_grp_id, site_grp_name, comp_idx, site_grp_img_path, site_grp_img_sname, site_grp_img_rname, del_yn, reg_uid, reg_date, mod_uid, mod_date 
from tb_site_group
where del_yn = 'N'
and site_grp_idx = #{siteGrpIdx }

/* 그룹ID 중복여부 체크 */
select 
	count(*) as cnt 
from tb_site_group
where del_yn = 'N'
and site_grp_id = #{siteGrpId }

/* 군관리메인 사이트 사용량 순위 누적/예상 총합 조회 */ select sum(usages) "usage", sum(charge) charge, sum(gen) gen, sum(reward) reward, sum(usage_plan) usage_plan, sum(charge_plan) charge_plan from ( select (select truncate(ifnull(sum(usg_val), 0) / 1000000, 0) from tb_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) usages, (select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge, (select ifnull(sum(gen_val), 0) from tb_pv_gen where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) gen, ( (select ifnull(sum(off_peak_rate + mid_peak_rate + max_peak_rate), 0) from tb_bill where site_id = a.site_id and bill_yearm between #{selTermFrom } and #{selTermTo }) + (select ifnull(sum(tot_price), 0) from tb_gen_revenue where site_id = a.site_id and gen_type = '1' and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) + (select ifnull(sum(((reduct_amt / reduct_cap) * 100) + 123), 0) from tb_dr_revenue where site_id = a.site_id and std_yearm between #{selTermFrom } and #{selTermTo }) ) reward,
(select truncate(ifnull(sum(pre_usg_val), 0) / 1000000, 0) from tb_predict_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) usage_plan, (select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge_plan where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge_plan from tb_site a, tb_site_group b where 1=1 and a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
) f_tb

/* 군관리메인 사이트 사용량 총합계 조회 */ select site_grp_name, site_grp_img_path, site_grp_img_sname,
sum(usages) "usage", sum(charge) charge, sum(gen) gen, sum(reward) reward from ( select b.site_grp_name, b.site_grp_img_path, b.site_grp_img_sname,
(select truncate(ifnull(sum(usg_val), 0) / 1000000, 0) from tb_usage where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) usages, (select ifnull(sum(chg_val), 0) + ifnull(sum(dischg_val), 0) from tb_ess_charge where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) charge, (select ifnull(sum(gen_val), 0) from tb_pv_gen where site_id = a.site_id and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) gen, ( (select ifnull(sum(off_peak_rate + mid_peak_rate + max_peak_rate), 0) from tb_bill where site_id = a.site_id and bill_yearm between #{selTermFrom } and #{selTermTo }) + (select ifnull(sum(tot_price), 0) from tb_gen_revenue where site_id = a.site_id and gen_type = '1' and std_date between str_to_date(#{selTermFrom },'%Y%m%d%H%i%s') and str_to_date(#{selTermTo },'%Y%m%d%H%i%s')) + (select ifnull(sum(((reduct_amt / reduct_cap) * 100) + 123), 0) from tb_dr_revenue where site_id = a.site_id and std_yearm between #{selTermFrom } and #{selTermTo }) ) reward from tb_site a, tb_site_group b where 1=1 and a.site_grp_idx = b.site_grp_idx and a.del_yn = 'N'
and a.user_idx = #{userIdx}
and a.area_type = #{areaType}
and b.site_grp_idx = #{grpIdx}
and b.user_idx = #{userIdx}
) f_tb

mapper.insert:
/* 회사 등록 */ insert into tb_company (
user_idx, /* 사용자식별자 */ comp_name, /* 회사명 */ comp_id, /* 회사ID */ del_yn, reg_uid, reg_date ) values (
#{userIdx }, #{compName }, #{compId }, 'N', #{regUid }, now() )

mapper.update:
/* 회사 정보 수정 */ update tb_company set
comp_name = #{compName }, /* 회사명 */
comp_id = #{compId }, /* 회사ID */
mod_uid = #{modUid }, mod_date = now() where 1=1 and comp_idx = #{compIdx }
